package com.example.bookservice.service;import com.example.bookservice.exception.HttpStatusException;import com.example.bookservice.model.Book;import com.example.bookservice.model.Review;import com.example.bookservice.model.ReviewAdminStatsDto;import com.example.bookservice.model.ReviewBookStatsDto;import com.example.bookservice.repository.BookRepository;import com.example.bookservice.repository.ReviewRepository;import org.junit.jupiter.api.BeforeEach;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.dao.DataIntegrityViolationException;import org.springframework.dao.EmptyResultDataAccessException;import org.springframework.data.domain.Sort;import org.springframework.http.HttpStatus;import java.time.LocalDateTime;import java.util.Arrays;import java.util.Collections;import java.util.List;import java.util.Optional;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.any;import static org.mockito.ArgumentMatchers.anyString;import static org.mockito.Mockito.*;@ExtendWith(MockitoExtension.class)class ReviewServiceTest {  @Mock private ReviewRepository reviewRepository;  @Mock private BookRepository bookRepository;  @InjectMocks private ReviewService reviewService;  private Review review;  private Book book;  @BeforeEach  void setUp() {    review = new Review();    review.setId(1L);    review.setAuthor("user1");    review.setBookName("Book1");    review.setRating(5);    review.setComment("Great book!");    review.setCreatedAt(LocalDateTime.now());    book = new Book(Collections.singletonList("user1"), "Book1", "Author1", "Genre1", "Desc1");    book.setId(1L);  }  @Test  void addReview_SaveReview() {    when(reviewRepository.existsByAuthorAndBookName("user1", "Book1")).thenReturn(false);    when(bookRepository.existsByNameIgnoreCase("Book1")).thenReturn(true);    when(bookRepository.findOwnersByBookName("Book1"))        .thenReturn(Collections.singletonList("user1"));    when(reviewRepository.save(any(Review.class))).thenReturn(review);    assertDoesNotThrow(() -> reviewService.addReview(review));    assertNotNull(review.getCreatedAt());    verify(reviewRepository, times(1)).save(review);  }  @Test  void addReview_ThrowConflictReviewExist() {    when(reviewRepository.existsByAuthorAndBookName("user1", "Book1")).thenReturn(true);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> reviewService.addReview(review));    assertEquals(HttpStatus.CONFLICT, exception.getHttpStatus());    assertEquals("Вы уже оставили отзыв на книгу Book1", exception.getMessage());  }  @Test  void addReview_ThrowConflictBookNotExist() {    when(reviewRepository.existsByAuthorAndBookName("user1", "Book1")).thenReturn(false);    when(bookRepository.existsByNameIgnoreCase("Book1")).thenReturn(false);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> reviewService.addReview(review));    assertEquals(HttpStatus.CONFLICT, exception.getHttpStatus());    assertEquals("Книга с названием Book1 не существует!", exception.getMessage());  }  @Test  void addReview_ThrowBadRequest() {    when(reviewRepository.existsByAuthorAndBookName("user1", "Book1")).thenReturn(false);    when(bookRepository.existsByNameIgnoreCase("Book1")).thenReturn(true);    when(bookRepository.findOwnersByBookName("Book1"))        .thenReturn(Collections.singletonList("otherUser"));    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> reviewService.addReview(review));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Вы не обладаете книгой с названием Book1", exception.getMessage());  }  @Test  void addReview_ThrowConflictElse() {    when(reviewRepository.existsByAuthorAndBookName("user1", "Book1")).thenReturn(false);    when(bookRepository.existsByNameIgnoreCase("Book1")).thenReturn(true);    when(bookRepository.findOwnersByBookName("Book1"))        .thenReturn(Collections.singletonList("user1"));    when(reviewRepository.save(any(Review.class))).thenThrow(DataIntegrityViolationException.class);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> reviewService.addReview(review));    assertEquals(HttpStatus.CONFLICT, exception.getHttpStatus());    assertEquals("Не удалось сохранить отзыв!", exception.getMessage());  }  @Test  void deleteReview_DeleteReview() {    doNothing().when(reviewRepository).deleteById(1L);    assertDoesNotThrow(() -> reviewService.deleteReview(1L));    verify(reviewRepository, times(1)).deleteById(1L);  }  @Test  void deleteReview_ThrowNotFound() {    doThrow(EmptyResultDataAccessException.class).when(reviewRepository).deleteById(1L);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> reviewService.deleteReview(1L));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertEquals("Отзыв с id  1 не найден!", exception.getMessage());  }  @Test  void getReviewStatsAboutBook_ReturnStats() {    List<Review> reviews =        Arrays.asList(review, new Review(2L, "user2", "Book1", 3, "Okay", LocalDateTime.now()));    when(bookRepository.findById(1L)).thenReturn(Optional.of(book));    when(reviewRepository.findByBookName("Book1")).thenReturn(reviews);    ReviewBookStatsDto stats = reviewService.getReviewStatsAboutBook(1L);    assertEquals(4.0, stats.getAvgRating());    assertEquals(2, stats.getCountRating());  }  @Test  void getReviewStatsAboutBook_ThrowNotFound() {    when(bookRepository.findById(1L)).thenReturn(Optional.empty());    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> reviewService.getReviewStatsAboutBook(1L));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertTrue(exception.getMessage().contains("Книга с id =   1 не найдена!"));  }  @Test  void getReviewStatsAboutBook_ReturnZeroStats() {    when(bookRepository.findById(1L)).thenReturn(Optional.of(book));    when(reviewRepository.findByBookName("Book1")).thenReturn(Collections.emptyList());    ReviewBookStatsDto stats = reviewService.getReviewStatsAboutBook(1L);    assertEquals(0.0, stats.getAvgRating());    assertEquals(0, stats.getCountRating());  }  @Test  void getReviewsById_ReturnListOfReviews() {    List<Review> reviews = Collections.singletonList(review);    when(bookRepository.findById(1L)).thenReturn(Optional.of(book));    when(reviewRepository.findByBookName("Book1")).thenReturn(reviews);    List<Review> foundReviews = reviewService.getReviewsById(1L);    assertFalse(foundReviews.isEmpty());    assertEquals(1, foundReviews.size());  }  @Test  void getReviewsById_ThrowNotFound() {    when(bookRepository.findById(1L)).thenReturn(Optional.empty());    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> reviewService.getReviewsById(1L));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertTrue(exception.getMessage().contains("Книга с id =   1 не найдена!"));  }  @Test  void getReviewsByAuthor_ReturnListOfReviews() {    List<Review> reviews = Collections.singletonList(review);    when(reviewRepository.findByAuthor("user1")).thenReturn(reviews);    List<Review> foundReviews = reviewService.getReviewsByAuthor("user1");    assertFalse(foundReviews.isEmpty());    assertEquals(1, foundReviews.size());  }  @Test  void getReviewsByDescCreatedAt_ReturnSortedListOfReviews() {    List<Review> reviews = Collections.singletonList(review);    when(reviewRepository.findAll(Sort.by(Sort.Direction.DESC, "createdAt"))).thenReturn(reviews);    List<Review> foundReviews = reviewService.getReviewsByDescCreatedAt();    assertFalse(foundReviews.isEmpty());    assertEquals(1, foundReviews.size());  }  @Test  void getReviewStatsForAdmin_ReturnCorrectStats() {    when(reviewRepository.count()).thenReturn(10L);    when(reviewRepository.countByRating(5)).thenReturn(5);    when(reviewRepository.countByRating(1)).thenReturn(1);    ReviewAdminStatsDto stats = reviewService.getReviewStatsForAdmin();    assertEquals(10L, stats.getCountReviews());    assertEquals(5L, stats.getCountRate5());    assertEquals(1L, stats.getCountRate1());  }}